// Input: Logical Address (segment_number, offset)
// Output: Physical Address or Fault

FUNCTION TranslateAddress(segment_number, offset)
BEGIN
    // Step 1: Check if segment number is valid
    IF segment_number >= MAX_SEGMENTS THEN
        RETURN FAULT_INVALID_SEGMENT
    END IF

    // Step 2: Get segment table entry
    seg_entry = SegmentTable[segment_number]

    // Step 3: Check if segment is in memory (valid bit)
    IF seg_entry.valid == FALSE THEN
        RETURN FAULT_SEGMENT_NOT_IN_MEMORY
    END IF

    // Step 4: Bounds checking - offset must be less than limit
    IF offset >= seg_entry.limit THEN
        RETURN FAULT_SEGMENTATION_FAULT
    END IF

    // Step 5: Check protection bits (assuming read operation)
    IF NOT seg_entry.protection.read THEN
        RETURN FAULT_PROTECTION_VIOLATION
    END IF

    // Step 6: Calculate physical address
    physical_address = seg_entry.base + offset

    RETURN physical_address
END FUNCTION

#include <stdio.h>
#include <stdbool.h>

// Segment table entry structure
struct SegmentEntry {
    unsigned int base;      // Starting physical address
    unsigned int limit;     // Segment size/length
    bool read:1;           // Read permission
    bool write:1;          // Write permission  
    bool execute:1;        // Execute permission
    bool valid:1;          // Present in memory
};

// Physical memory array
unsigned char physical_memory[65536];

// Maximum number of segments
#define MAX_SEGMENTS 16

struct SegmentEntry segment_table[MAX_SEGMENTS];

// Initialize segment table
void init_segment_table() {
    for (int i = 0; i < MAX_SEGMENTS; i++) {
        segment_table[i].base = 0;
        segment_table[i].limit = 0;
        segment_table[i].read = segment_table[i].write = false;
        segment_table[i].execute = segment_table[i].valid = false;
    }
}

// Create a new segment
void create_segment(int seg_num, unsigned int base, unsigned int limit, 
                   bool r, bool w, bool x) {
    if (seg_num >= MAX_SEGMENTS) {
        printf("Error: Invalid segment number\n");
        return;
    }
    segment_table[seg_num].base = base;
    segment_table[seg_num].limit = limit;
    segment_table[seg_num].read = r;
    segment_table[seg_num].write = w;
    segment_table[seg_num].execute = x;
    segment_table[seg_num].valid = true;
    printf("Segment %d created: base=%u, limit=%u\n", seg_num, base, limit);
}

// Address translation function
unsigned int translate_address(int seg_num, unsigned int offset) {
    if (seg_num >= MAX_SEGMENTS || !segment_table[seg_num].valid) {
        printf("Segmentation Fault: Invalid segment\n");
        return 0xFFFFFFFF;
    }

    if (offset >= segment_table[seg_num].limit) {
        printf("Segmentation Fault: Offset %u >= Limit %u\n", 
               offset, segment_table[seg_num].limit);
        return 0xFFFFFFFF;
    }

    if (!segment_table[seg_num].read) {
        printf("Protection Fault: Read not allowed\n");
        return 0xFFFFFFFF;
    }

    return segment_table[seg_num].base + offset;
}

int main() {
    init_segment_table();

    // Create code segment (read+execute, no write)
    create_segment(0, 1000, 500, true, false, true);

    // Create data segment (read+write)
    create_segment(1, 2000, 1000, true, true, false);

    // Translate addresses
    unsigned int phys_addr = translate_address(0, 100);
    printf("Logical(0, 100) -> Physical: %u\n", phys_addr);  // 1100

    phys_addr = translate_address(1, 500);
    printf("Logical(1, 500) -> Physical: %u\n", phys_addr);  // 2500

    // Test error cases
    translate_address(0, 600);  // Should fail: exceeds limit

    return 0;
}

// Combined Segmentation-Paging Address Translation
// Logical Address: [Segment Number | Page Number | Page Offset]
// Total bits: s bits for segment, p bits for page, d bits for offset

FUNCTION TranslateSegPaging(seg_num, page_num, page_offset)
BEGIN
    // Step 1: Segment Translation
    IF seg_num >= MAX_SEGMENTS THEN
        RETURN FAULT_INVALID_SEGMENT
    END IF

    seg_entry = SegmentTable[seg_num]

    IF NOT seg_entry.valid THEN
        RETURN FAULT_SEGMENT_NOT_IN_MEMORY
    END IF

    // Check segment-level protection
    IF NOT seg_entry.protection[read] THEN
        RETURN FAULT_PROTECTION_VIOLATION
    END IF

    // Step 2: Check page offset within segment
    virtual_page_addr = (page_num * PAGE_SIZE) + page_offset
    IF virtual_page_addr >= seg_entry.limit THEN
        RETURN FAULT_SEGMENTATION_FAULT
    END IF

    // Step 3: Page Translation within segment
    // Use segment's page table
    page_table_entry = seg_entry.page_table[page_num]

    IF NOT page_table_entry.valid THEN
        RETURN PAGE_FAULT
    END IF

    // Step 4: Generate Physical Address
    frame_number = page_table_entry.frame_number
    physical_address = (frame_number * PAGE_SIZE) + page_offset

    RETURN physical_address
END FUNCTION

